import "./Header.css";

function Header() {
  const handleLogout = () => {
    alert("Logged out");
  };

  return (
    <div className="header">
      <h3>Welcome, Admin</h3>
      <button className="logout-btn" onClick={handleLogout}>
        Logout
      </button>
    </div>
  );
}

export default Header;
